#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *xs = (int*)malloc(N*sizeof(int));
        int *ys = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d %d", &xs[i], &ys[i]);
        qsort(xs,N,sizeof(int),cmp);
        qsort(ys,N,sizeof(int),cmp);
        int uniqX=0, uniqY=0;
        for(int i=0;i<N;i++) if(i==0||xs[i]!=xs[i-1]) uniqX++;
        for(int i=0;i<N;i++) if(i==0||ys[i]!=ys[i-1]) uniqY++;
        printf("%d\n", uniqX+uniqY);
        free(xs); free(ys);
    }
    return 0;
}

